use std::env;

const BASE: u64 = 1_000_000_000;

#[derive(Clone)]
struct DecimalBigUint {
    limbs: Vec<u32>,
}

impl DecimalBigUint {
    fn zero() -> Self {
        Self { limbs: Vec::new() }
    }

    fn one() -> Self {
        Self { limbs: vec![1] }
    }

    fn normalize(mut self) -> Self {
        while self.limbs.last() == Some(&0) {
            self.limbs.pop();
        }
        self
    }

    fn is_zero(&self) -> bool {
        self.limbs.is_empty()
    }

    fn add(&self, other: &Self) -> Self {
        let len = self.limbs.len().max(other.limbs.len());
        let mut out = Vec::with_capacity(len + 1);
        let mut carry = 0_u64;
        for index in 0..len {
            let left = self.limbs.get(index).copied().unwrap_or(0) as u64;
            let right = other.limbs.get(index).copied().unwrap_or(0) as u64;
            let sum = left + right + carry;
            out.push((sum % BASE) as u32);
            carry = sum / BASE;
        }
        if carry > 0 {
            out.push(carry as u32);
        }
        Self { limbs: out }.normalize()
    }

    fn sub(&self, other: &Self) -> Self {
        let mut out = Vec::with_capacity(self.limbs.len());
        let mut borrow = 0_i64;
        for index in 0..self.limbs.len() {
            let left = self.limbs[index] as i64 - borrow;
            let right = other.limbs.get(index).copied().unwrap_or(0) as i64;
            if left >= right {
                out.push((left - right) as u32);
                borrow = 0;
            } else {
                out.push((left + BASE as i64 - right) as u32);
                borrow = 1;
            }
        }
        Self { limbs: out }.normalize()
    }

    fn double(&self) -> Self {
        self.add(self)
    }

    fn mul(&self, other: &Self) -> Self {
        if self.is_zero() || other.is_zero() {
            return Self::zero();
        }

        let mut out = vec![0_u64; self.limbs.len() + other.limbs.len()];
        for (left_index, left) in self.limbs.iter().enumerate() {
            let left = *left as u64;
            let mut carry = 0_u64;
            for (right_index, right) in other.limbs.iter().enumerate() {
                let out_index = left_index + right_index;
                let product = out[out_index] + left * (*right as u64) + carry;
                out[out_index] = product % BASE;
                carry = product / BASE;
            }
            let mut out_index = left_index + other.limbs.len();
            while carry > 0 {
                if out_index == out.len() {
                    out.push(0);
                }
                let sum = out[out_index] + carry;
                out[out_index] = sum % BASE;
                carry = sum / BASE;
                out_index += 1;
            }
        }

        Self {
            limbs: out.into_iter().map(|limb| limb as u32).collect(),
        }
        .normalize()
    }

    fn to_decimal_string(&self) -> String {
        let Some((last, rest)) = self.limbs.split_last() else {
            return "0".to_string();
        };
        let mut out = last.to_string();
        for limb in rest.iter().rev() {
            out.push_str(&format!("{limb:09}"));
        }
        out
    }
}

fn fibonacci_pair(n: u32) -> (DecimalBigUint, DecimalBigUint) {
    if n == 0 {
        return (DecimalBigUint::zero(), DecimalBigUint::one());
    }
    let (a, b) = fibonacci_pair(n / 2);
    let c = a.mul(&b.double().sub(&a));
    let d = a.mul(&a).add(&b.mul(&b));
    if n % 2 == 0 {
        (c, d)
    } else {
        (d.clone(), c.add(&d))
    }
}

fn parse_input_n(input: &str) -> u32 {
    let marker = "\"n\":";
    let Some(start) = input.find(marker).map(|index| index + marker.len()) else {
        return 0;
    };
    let digits: String = input[start..]
        .chars()
        .skip_while(|c| c.is_whitespace())
        .take_while(|c| c.is_ascii_digit())
        .collect();
    digits.parse::<u32>().unwrap_or(0)
}

fn main() {
    let input = env::args().nth(1).unwrap_or_else(|| "{\"n\":0}".to_string());
    let n = parse_input_n(&input);
    println!("{}", fibonacci_pair(n).0.to_decimal_string());
}
